export function webMercatorMeters(lon, lat) {
  const limitedLat = Math.max(-85.05112878, Math.min(85.05112878, lat));
  return {
    x: EARTH_RADIUS * lon * DEG,
    y: EARTH_RADIUS * Math.log(Math.tan(Math.PI / 4 + limitedLat * DEG / 2)),
  };
}

function projectionMetrics(bbox = BBOX, metersPerTile = METERS_PER_TILE) {
  const [minLon, minLat, maxLon, maxLat] = bbox;
  const southWest = webMercatorMeters(minLon, minLat);
  const northEast = webMercatorMeters(maxLon, maxLat);
  const correction = Math.cos(((minLat + maxLat) / 2) * DEG);
  const widthMeters = (northEast.x - southWest.x) * correction;
  const heightMeters = (northEast.y - southWest.y) * correction;
  return {
    southWest,
    northEast,
    correction,
    widthMeters,
    heightMeters,
    grid: {
      w: Math.ceil(widthMeters / metersPerTile),
      h: Math.ceil(heightMeters / metersPerTile),
    },
  };
}

const METRICS = projectionMetrics();

export const FUKUOKA_META = Object.freeze({
  city: 'fukuoka',
  bbox: BBOX,
  grid: Object.freeze(METRICS.grid),
  metersPerTile: METERS_PER_TILE,
  projection: 'webmercator',
  aspectCorrection: Number(METRICS.correction.toFixed(12)),
  source: Object.freeze({
    geometry: 'OpenStreetMap contributors',
    license: 'ODbL-1.0',
    snapshot: '2026-07-13',
    buildingWays: OSM_SNAPSHOT.source.buildingWays,
    roadWays: OSM_SNAPSHOT.source.roadWays,
    crossingNodes: OSM_SNAPSHOT.source.crossingNodes,
    namedRoadWays: OSM_SNAPSHOT.source.namedRoadWays,
  }),
});

export function projectLatLonToGrid(lat, lon, meta = FUKUOKA_META) {
  const metrics = meta === FUKUOKA_META ? METRICS : projectionMetrics(meta.bbox, meta.metersPerTile);
  const point = webMercatorMeters(lon, lat);
  return {
    x: ((point.x - metrics.southWest.x) * metrics.correction) / meta.metersPerTile,
    y: ((metrics.northEast.y - point.y) * metrics.correction) / meta.metersPerTile,
  };
}

export function projectLatLonToTile(lat, lon, meta = FUKUOKA_META) {
  const point = projectLatLonToGrid(lat, lon, meta);
  return [
    Math.max(0, Math.min(meta.grid.w - 1, Math.floor(point.x))),
    Math.max(0, Math.min(meta.grid.h - 1, Math.floor(point.y))),
  ];
}

function projectedPolygon(points) {
  return points.map(([lon, lat]) => {
    const point = projectLatLonToGrid(lat, lon);
    return [point.x, point.y];
  });
}

function setTile(grid, x, y, code) {
  const tx = Math.round(x);
  const ty = Math.round(y);
  if (tx < 0 || ty < 0 || tx >= FUKUOKA_META.grid.w || ty >= FUKUOKA_META.grid.h) return;
  grid[ty * FUKUOKA_META.grid.w + tx] = code;
}

function fillCircle(grid, cx, cy, radius, code, filter = null) {
  const minX = Math.floor(cx - radius);
  const maxX = Math.ceil(cx + radius);
  const minY = Math.floor(cy - radius);
  const maxY = Math.ceil(cy + radius);
  for (let y = minY; y <= maxY; y += 1) {
    for (let x = minX; x <= maxX; x += 1) {
      if ((x - cx) ** 2 + (y - cy) ** 2 > (radius + 0.35) ** 2) continue;
      if (x < 0 || y < 0 || x >= FUKUOKA_META.grid.w || y >= FUKUOKA_META.grid.h) continue;
      const index = y * FUKUOKA_META.grid.w + x;
      grid[index] = filter ? filter(grid[index]) : code;
    }
  }
}

function fillPolygon(grid, lonLatPoints, code) {
  const points = projectedPolygon(lonLatPoints);
  const minY = Math.max(0, Math.floor(Math.min(...points.map((point) => point[1]))));
  const maxY = Math.min(FUKUOKA_META.grid.h - 1, Math.ceil(Math.max(...points.map((point) => point[1]))));
  for (let y = minY; y <= maxY; y += 1) {
    const scanY = y + 0.5;
    const intersections = [];
    for (let i = 0; i < points.length; i += 1) {
      const a = points[i];
      const b = points[(i + 1) % points.length];
      if ((a[1] > scanY) === (b[1] > scanY)) continue;
      intersections.push(a[0] + ((scanY - a[1]) * (b[0] - a[0])) / (b[1] - a[1]));
    }
    intersections.sort((a, b) => a - b);
    for (let i = 0; i + 1 < intersections.length; i += 2) {
      const start = Math.max(0, Math.ceil(intersections[i]));
      const end = Math.min(FUKUOKA_META.grid.w - 1, Math.floor(intersections[i + 1]));
      for (let x = start; x <= end; x += 1) grid[y * FUKUOKA_META.grid.w + x] = code;
    }
  }
}

function drawPolyline(grid, lonLatPoints, radius, painter) {
  const points = projectedPolygon(lonLatPoints);
  for (let i = 1; i < points.length; i += 1) {
    const [x0, y0] = points[i - 1];
    const [x1, y1] = points[i];
    const steps = Math.max(1, Math.ceil(Math.max(Math.abs(x1 - x0), Math.abs(y1 - y0)) * 2));
    for (let step = 0; step <= steps; step += 1) {
      const t = step / steps;
      fillCircle(grid, x0 + (x1 - x0) * t, y0 + (y1 - y0) * t, radius, 0, painter);
    }
  }
}

function fillEllipse(grid, lat, lon, radiusX, radiusY, code) {
  const center = projectLatLonToGrid(lat, lon);
  for (let y = Math.floor(center.y - radiusY); y <= Math.ceil(center.y + radiusY); y += 1) {
    for (let x = Math.floor(center.x - radiusX); x <= Math.ceil(center.x + radiusX); x += 1) {
      if (((x - center.x) / radiusX) ** 2 + ((y - center.y) / radiusY) ** 2 > 1) continue;
      setTile(grid, x, y, code);
    }
  }
}

function polygonCentroid(points) {
  let twiceArea = 0;
  let x = 0;
  let y = 0;
  for (let i = 0; i < points.length; i += 1) {
    const a = points[i];
    const b = points[(i + 1) % points.length];
    const cross = a[0] * b[1] - b[0] * a[1];
    twiceArea += cross;
    x += (a[0] + b[0]) * cross;
    y += (a[1] + b[1]) * cross;
  }
  if (Math.abs(twiceArea) < Number.EPSILON) {
    const total = points.reduce((sum, point) => [sum[0] + point[0], sum[1] + point[1]], [0, 0]);
    return { lon: total[0] / points.length, lat: total[1] / points.length };
  }
  return { lon: x / (3 * twiceArea), lat: y / (3 * twiceArea) };
}

function poiFromPolygon(id, nameJa, yomi, polygonId, kind) {
  const center = polygonCentroid(SOURCE_VECTORS.polygons[polygonId]);
  return { id, nameJa, yomi, lat: center.lat, lon: center.lon, kind };
}

const POI_SOURCE = Object.freeze([
  poiFromPolygon('momochi-seaside', 'シーサイドももち海浜公園', 'しーさいどももちかいひんこうえん', '900420523', 'beach'),
  poiFromPolygon('fukuoka-tower', '福岡タワー', 'ふくおかたわー', '772670439', 'landmark'),
  poiFromPolygon('marizon', 'マリゾン', 'まりぞん', '224085938', 'waterfront'),
  poiFromPolygon('paypay-dome', 'PayPayドーム', 'ぺいぺいどーむ', '28445837', 'stadium'),
  poiFromPolygon('fukuoka-museum', '福岡市博物館', 'ふくおかしはくぶつかん', '210616030', 'museum'),
  poiFromPolygon('ohori-park', '大濠公園', 'おおほりこうえん', '23344558', 'park'),
  poiFromPolygon('fukuoka-castle', '福岡城跡', 'ふくおかじょうあと', '345642780', 'historic'),
  poiFromPolygon('acros-fukuoka', 'アクロス福岡', 'あくろすふくおか', '33111546', 'landmark'),
  { id: 'nakasu', nameJa: '中洲', yomi: 'なかす', lat: 33.5929, lon: 130.406, kind: 'district' },
  poiFromPolygon('kushida-jinja', '櫛田神社', 'くしだじんじゃ', '45779975', 'shrine'),
  poiFromPolygon('canal-city', 'キャナルシティ博多', 'きゃなるしてぃはかた', '751001483', 'shopping'),
  poiFromPolygon('hakata-port-tower', '博多ポートタワー', 'はかたぽーとたわー', '684600217', 'landmark'),
  poiFromPolygon('bayside-place', 'ベイサイドプレイス博多', 'べいさいどぷれいすはかた', '168100626', 'waterfront'),
  {
    id: 'hakata-port-international-terminal',
    nameJa: '博多港国際ターミナル',
    yomi: 'はかたこうこくさいたーみなる',
    lat: OSM_SNAPSHOT.features.hakataPortInternationalTerminal.lat,
    lon: OSM_SNAPSHOT.features.hakataPortInternationalTerminal.lon,
    kind: 'ferry-terminal',
  },
]);

function assertSnapshotContract() {
  if (JSON.stringify(OSM_SNAPSHOT.bbox) !== JSON.stringify(FUKUOKA_META.bbox)) {
    throw new Error('Fukuoka OSM snapshot bbox mismatch');
  }
  if (OSM_SNAPSHOT.grid.w !== FUKUOKA_META.grid.w || OSM_SNAPSHOT.grid.h !== FUKUOKA_META.grid.h) {
    throw new Error('Fukuoka OSM snapshot grid mismatch');
  }
}

function isBlockedCode(code) {
  return code === CITY_TILE.WATER
    || code === CITY_TILE.RIVER
    || code === CITY_TILE.BUILDING
    || code === CITY_TILE.ISLAND;
}

function paintHakataBay(grid) {
  const { w, h } = FUKUOKA_META.grid;
  const barrier = new Uint8Array(grid.length);
  drawPolyline(barrier, SOURCE_VECTORS.coast, 1.05, () => 1);

  let start = -1;
  for (let y = 0; y < 8 && start < 0; y += 1) {
    for (let x = 0; x < Math.floor(w / 2); x += 1) {
      const index = y * w + x;
      if (!barrier[index]) {
        start = index;
        break;
      }
    }
  }
  if (start < 0) throw new Error('Hakata Bay water seed not found');

  const seen = new Uint8Array(grid.length);
  const queue = new Int32Array(grid.length);
  let head = 0;
  let tail = 0;
  queue[tail++] = start;
  seen[start] = 1;
  const safetySouth = Math.floor(h * 0.62);
  while (head < tail) {
    const index = queue[head++];
    const x = index % w;
    const y = Math.floor(index / w);
    grid[index] = CITY_TILE.WATER;
    for (const [dx, dy] of [[1, 0], [-1, 0], [0, 1], [0, -1]]) {
      const nx = x + dx;
      const ny = y + dy;
      if (nx < 0 || ny < 0 || nx >= w || ny >= safetySouth) continue;
      const next = ny * w + nx;
      if (seen[next] || barrier[next]) continue;
      seen[next] = 1;
      queue[tail++] = next;
    }
  }
}

function applyOsmBuildings(grid, buildingMask) {
  for (let index = 0; index < grid.length; index += 1) {
    if (!buildingMask[index]) continue;
    if (grid[index] === CITY_TILE.WATER || grid[index] === CITY_TILE.RIVER) continue;
    grid[index] = CITY_TILE.BUILDING;
  }
}

function applyOsmRoads(grid, roadMask) {
  for (let index = 0; index < grid.length; index += 1) {
    const roadClass = roadMask[index];
    if (!roadClass) continue;
    const previous = grid[index];
    if (previous === CITY_TILE.WATER || previous === CITY_TILE.RIVER || previous === CITY_TILE.BRIDGE) {
      grid[index] = CITY_TILE.BRIDGE;
    } else if (roadClass >= 2) {
      grid[index] = CITY_TILE.ROAD;
    } else if (previous !== CITY_TILE.BUILDING) {
      grid[index] = CITY_TILE.SIDEWALK;
    }
  }
}

function paintCrosswalks(grid, roadMask) {
  const { w, h } = FUKUOKA_META.grid;
  for (const [x, y] of OSM_SNAPSHOT.crossings) {
    if (x < 0 || y < 0 || x >= w || y >= h) continue;
    const index = y * w + x;
    if (roadMask[index] >= 2 && grid[index] === CITY_TILE.ROAD) grid[index] = CITY_TILE.CROSSWALK;
  }
}

function paintCanalCityCourtyard(grid) {
  const polygon = SOURCE_VECTORS.polygons['751001483'];
  const center = polygonCentroid(polygon);
  fillPolygon(grid, polygon, CITY_TILE.BUILDING);
  fillEllipse(grid, center.lat, center.lon, 4.1, 6.4, CITY_TILE.PLAZA);
  const point = projectLatLonToGrid(center.lat, center.lon);
  fillCircle(grid, point.x - 5.2, point.y, 1.15, CITY_TILE.PLAZA);
  fillCircle(grid, point.x + 5.2, point.y, 1.15, CITY_TILE.PLAZA);
}

function paintHakataStation(grid, buildingMask) {
  const station = STATION_SOURCE.find((entry) => entry.id === 'hakata');
  const point = projectLatLonToGrid(station.lat, station.lon);
  for (let y = Math.floor(point.y - 12); y <= Math.ceil(point.y + 12); y += 1) {
    for (let x = Math.floor(point.x - 6); x <= Math.ceil(point.x + 8); x += 1) {
      if (x < 0 || y < 0 || x >= FUKUOKA_META.grid.w || y >= FUKUOKA_META.grid.h) continue;
      const index = y * FUKUOKA_META.grid.w + x;
      if (buildingMask[index]) grid[index] = CITY_TILE.BUILDING;
    }
  }
  fillEllipse(grid, 33.59005, 130.41875, 5.4, 7.3, CITY_TILE.PLAZA);
  fillCircle(grid, point.x, point.y, 0.75, CITY_TILE.PLAZA);
}

function ensureWalkableAnchor(grid, entry) {
  const [x, y] = projectLatLonToTile(entry.lat, entry.lon);
  const { w, h } = FUKUOKA_META.grid;
  const index = y * w + x;
  if (isBlockedCode(grid[index])) grid[index] = CITY_TILE.PLAZA;
  for (const [dx, dy] of [[1, 0], [-1, 0], [0, 1], [0, -1]]) {
    const nx = x + dx;
    const ny = y + dy;
    if (nx < 0 || ny < 0 || nx >= w || ny >= h) continue;
    if (!isBlockedCode(grid[ny * w + nx])) return;
  }
  const nx = x > 0 ? x - 1 : x + 1;
  grid[y * w + nx] = CITY_TILE.PLAZA;
}

function reachableFrom(grid, start) {
  const { w, h } = FUKUOKA_META.grid;
  const seen = new Uint8Array(grid.length);
  const queue = new Int32Array(grid.length);
  let head = 0;
  let tail = 0;
  queue[tail++] = start;
  seen[start] = 1;
  while (head < tail) {
    const index = queue[head++];
    const x = index % w;
    const y = Math.floor(index / w);
    for (const [dx, dy] of [[1, 0], [-1, 0], [0, 1], [0, -1]]) {
      const nx = x + dx;
      const ny = y + dy;
      if (nx < 0 || ny < 0 || nx >= w || ny >= h) continue;
      const next = ny * w + nx;
      if (seen[next] || isBlockedCode(grid[next])) continue;
      seen[next] = 1;
      queue[tail++] = next;
    }
  }
  return seen;
}

function collectComponent(grid, start, visited) {
  const { w, h } = FUKUOKA_META.grid;
  const queue = [start];
  const component = [];
  visited[start] = 1;
  for (let head = 0; head < queue.length; head += 1) {
    const index = queue[head];
    component.push(index);
    const x = index % w;
    const y = Math.floor(index / w);
    for (const [dx, dy] of [[1, 0], [-1, 0], [0, 1], [0, -1]]) {
      const nx = x + dx;
      const ny = y + dy;
      if (nx < 0 || ny < 0 || nx >= w || ny >= h) continue;
      const next = ny * w + nx;
      if (visited[next] || isBlockedCode(grid[next])) continue;
      visited[next] = 1;
      queue.push(next);
    }
  }
  return component;
}

function connectToMain(grid, start, mainSeen) {
  const { w, h } = FUKUOKA_META.grid;
  const parent = new Int32Array(grid.length).fill(-1);
  const queue = new Int32Array(grid.length);
  let head = 0;
  let tail = 0;
  queue[tail++] = start;
  parent[start] = start;
  let target = -1;
  while (head < tail && target < 0) {
    const index = queue[head++];
    const x = index % w;
    const y = Math.floor(index / w);
    for (const [dx, dy] of [[1, 0], [-1, 0], [0, 1], [0, -1]]) {
      const nx = x + dx;
      const ny = y + dy;
      if (nx < 0 || ny < 0 || nx >= w || ny >= h) continue;
      const next = ny * w + nx;
      if (parent[next] >= 0) continue;
      parent[next] = index;
      if (mainSeen[next]) {
        target = next;
        break;
      }
      queue[tail++] = next;
    }
  }
  if (target < 0) throw new Error('Unable to connect walkable Fukuoka component');
  for (let index = target; index !== start; index = parent[index]) {
    if (!isBlockedCode(grid[index])) continue;
    grid[index] = grid[index] === CITY_TILE.WATER || grid[index] === CITY_TILE.RIVER
      ? CITY_TILE.BRIDGE
      : CITY_TILE.ROAD;
  }
}

function normalizeWalkableComponents(grid, protectedEntries) {
  const { w } = FUKUOKA_META.grid;
  const mainEntry = STATION_SOURCE.find((entry) => entry.id === 'tenjin');
  const [mainX, mainY] = projectLatLonToTile(mainEntry.lat, mainEntry.lon);
  const mainStart = mainY * w + mainX;
  const protectedTiles = new Set(protectedEntries.map((entry) => {
    const [x, y] = projectLatLonToTile(entry.lat, entry.lon);
    return y * w + x;
  }));

  const mainSeen = reachableFrom(grid, mainStart);
  const visited = mainSeen.slice();
  for (let index = 0; index < grid.length; index += 1) {
    if (visited[index] || isBlockedCode(grid[index])) continue;
    const component = collectComponent(grid, index, visited);
    const protectedComponent = component.some((tileIndex) => protectedTiles.has(tileIndex));
    const specialComponent = component.some((tileIndex) => [
      CITY_TILE.PARK, CITY_TILE.BEACH, CITY_TILE.DOCK, CITY_TILE.BRIDGE,
    ].includes(grid[tileIndex]));
    if (component.length < 24 && !protectedComponent && !specialComponent) {
      for (const tileIndex of component) grid[tileIndex] = CITY_TILE.BUILDING;
    } else {
      connectToMain(grid, component[0], mainSeen);
    }
  }

  const finalSeen = reachableFrom(grid, mainStart);
  for (let index = 0; index < grid.length; index += 1) {
    if (!isBlockedCode(grid[index]) && !finalSeen[index]) {
      throw new Error(`Disconnected Fukuoka walkable tile at ${index % w},${Math.floor(index / w)}`);
    }
  }
}

function createTerrain() {
  assertSnapshotContract();
  const grid = new Uint8Array(FUKUOKA_META.grid.w * FUKUOKA_META.grid.h).fill(CITY_TILE.SIDEWALK);
  const buildingMask = decodeTerrainRle(OSM_SNAPSHOT.buildingRle, grid.length);
  const roadMask = decodeTerrainRle(OSM_SNAPSHOT.roadRle, grid.length);

  paintHakataBay(grid);
  for (const polygonId of ['23344558', '345642780']) {
    fillPolygon(grid, SOURCE_VECTORS.polygons[polygonId], CITY_TILE.PARK);
  }
  fillPolygon(grid, SOURCE_VECTORS.polygons['900420523'], CITY_TILE.BEACH);
  fillEllipse(grid, 33.5862, 130.3768, 13, 22, CITY_TILE.WATER);

  const riverRadius = { '那珂川': 1.4, '御笠川': 1.25, '博多川': 0.65, '御笠川放水路': 0.85 };
  for (const river of SOURCE_VECTORS.rivers) {
    drawPolyline(grid, river.points, riverRadius[river.name], () => CITY_TILE.RIVER);
  }

  applyOsmBuildings(grid, buildingMask);
  for (const polygonId of ['28445837', '210616030', '33111546', '45779975', '772670439', '684600217']) {
    fillPolygon(grid, SOURCE_VECTORS.polygons[polygonId], CITY_TILE.BUILDING);
  }
  for (const polygonId of ['224085938', '900420540']) {
    fillPolygon(grid, SOURCE_VECTORS.polygons[polygonId], CITY_TILE.DOCK);
  }

  applyOsmRoads(grid, roadMask);
  for (const road of SOURCE_VECTORS.roads) {
    const radius = road.highway === 'primary' || road.highway === 'trunk' ? 1.05 : 0.55;
    drawPolyline(grid, road.points, radius, (previous) => (
      previous === CITY_TILE.RIVER || previous === CITY_TILE.WATER || previous === CITY_TILE.BRIDGE
        ? CITY_TILE.BRIDGE
        : CITY_TILE.ROAD
    ));
  }
  paintCrosswalks(grid, roadMask);
  paintCanalCityCourtyard(grid);
  paintHakataStation(grid, buildingMask);

  const protectedEntries = [...POI_SOURCE, ...STATION_SOURCE];
  for (const entry of protectedEntries) ensureWalkableAnchor(grid, entry);
  normalizeWalkableComponents(grid, protectedEntries);
  for (const entry of protectedEntries) ensureWalkableAnchor(grid, entry);

  return grid;
}

export function encodeTerrainRle(terrain) {
  if (terrain.length === 0) return [];
  const runs = [];
  let code = terrain[0];
  let count = 1;
  for (let i = 1; i < terrain.length; i += 1) {
    if (terrain[i] === code) {
      count += 1;
      continue;
    }
    runs.push([code, count]);
    code = terrain[i];
    count = 1;
  }
  runs.push([code, count]);
  return runs;
}

export function decodeTerrainRle(runs, length) {
  const terrain = new Uint8Array(length);
  let offset = 0;
  for (const [code, count] of runs) {
    terrain.fill(code, offset, offset + count);
    offset += count;
  }
  if (offset !== length) throw new Error(`terrain RLE length mismatch: ${offset} !== ${length}`);
  return terrain;
}

function withTile(entry) {
  return {
    ...entry,
    lat: Number(entry.lat.toFixed(7)),
    lon: Number(entry.lon.toFixed(7)),
    tile: projectLatLonToTile(entry.lat, entry.lon),
  };
}

export function buildFukuokaGeo() {
  return {
    meta: FUKUOKA_META,
    terrain: createTerrain(),
    pois: POI_SOURCE.map(withTile),
    stations: STATION_SOURCE.map(withTile),
  };
}

function generatedModule(geo) {
  const runs = encodeTerrainRle(geo.terrain);
  return `// Generated by scripts/build-fukuoka-geo.mjs. Do not edit by hand.\n// Geometry: © OpenStreetMap contributors, ODbL 1.0 (snapshot 2026-07-13).\n\nconst META = Object.freeze(${JSON.stringify(geo.meta, null, 2)});\nconst TERRAIN_RLE = ${JSON.stringify(runs)};\n\nfunction decodeTerrain(runs, length) {\n  const terrain = new Uint8Array(length);\n  let offset = 0;\n  for (const [code, count] of runs) {\n    terrain.fill(code, offset, offset + count);\n    offset += count;\n  }\n  if (offset !== length) throw new Error(\`terrain RLE length mismatch: \${offset} !== \${length}\`);\n  return terrain;\n}\n\nexport const FUKUOKA_GEO = Object.freeze({\n  meta: META,\n  terrain: decodeTerrain(TERRAIN_RLE, META.grid.w * META.grid.h),\n  pois: Object.freeze(${JSON.stringify(geo.pois, null, 2)}),\n  stations: Object.freeze(${JSON.stringify(geo.stations, null, 2)}),\n});\n`;
}

export function writeFukuokaGeo(outputPath = path.resolve(path.dirname(fileURLToPath(import.meta.url)), '../src/components/world/cities/fukuoka.geo.js')) {
  const geo = buildFukuokaGeo();
  fs.writeFileSync(outputPath, generatedModule(geo));
  return { outputPath, grid: geo.meta.grid, cells: geo.terrain.length, runs: encodeTerrainRle(geo.terrain).length };
}

if (process.argv[1] && path.resolve(process.argv[1]) === fileURLToPath(import.meta.url)) {
  console.log(JSON.stringify(writeFukuokaGeo()));
}
